CREATE TABLE `otp_verifications` (
	`id` int AUTO_INCREMENT NOT NULL,
	`phoneOrEmail` varchar(320) NOT NULL,
	`code` varchar(6) NOT NULL,
	`type` enum('phone','email') NOT NULL,
	`expiresAt` timestamp NOT NULL,
	`attempts` int NOT NULL DEFAULT 0,
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	CONSTRAINT `otp_verifications_id` PRIMARY KEY(`id`)
);
ALTER TABLE `users` MODIFY COLUMN `openId` varchar(64);
ALTER TABLE `users` ADD `phone` varchar(20);
ALTER TABLE `users` ADD `passwordHash` varchar(255);
ALTER TABLE `users` ADD `provider` enum('email','phone','google','manus') NOT NULL DEFAULT 'manus';
ALTER TABLE `users` ADD `isVerified` boolean DEFAULT false NOT NULL;
ALTER TABLE `users` ADD CONSTRAINT `users_phone_unique` UNIQUE(`phone`);
ALTER TABLE `users` ADD CONSTRAINT `users_email_unique` UNIQUE(`email`);

